#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int a[101][101];
        for (int i = 1; i <= N; ++i) {
            for (int j = 1; j <= i; ++j) {
                scanf("%d", &a[i][j]);
            }
        }
        int dp[101][101];
        for (int j = 1; j <= N; ++j) dp[N][j] = a[N][j];
        for (int i = N-1; i >= 1; --i) {
            for (int j = 1; j <= i; ++j) {
                dp[i][j] = a[i][j] + (dp[i+1][j] > dp[i+1][j+1] ? dp[i+1][j] : dp[i+1][j+1]);
            }
        }
        printf("%d\n", dp[1][1]);
    }
    return 0;
}

